function normalizeAirportName(name: string) {
  return name.replace(/\s+/g, ' ').trim()
}

export function slugifyInfrastructureId(value: string) {
  return value
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
}

function airportNote(featured: boolean) {
  if (featured) {
    return 'Featured commercial airport in the national overlay.'
  }

  return 'Commercial airport shown in the expanded overlay and in state-focused views.'
}

function importanceFromFeatured(featured: boolean): InfrastructureMarkerImportance {
  return featured ? 3 : 1
}

export function universitySubtitle(rank: number, city: string, stateCode: string) {
  return `U.S. News National Universities #${rank} · ${city}, ${stateCode}`
}

export function universityNote(rank: number) {
  return `Placed at No. ${rank} in the 2026 U.S. News National Universities ranking. This layer includes every school ranked 30 or better, which yields 31 schools because of ties.`
}

export function nuclearImportanceFromUnitCount(unitCount: number): InfrastructureMarkerImportance {
  return unitCount >= 3 ? 3 : 2
}

export function nuclearSubtitle(unitCount: number, stateCode: string) {
  return `${unitCount} reactor unit${unitCount === 1 ? '' : 's'} · ${stateCode}`
}

export function nuclearNote(unitCount: number) {
  return `Operating commercial nuclear reactor site in the current NRC reactor map. This site-level marker represents ${unitCount} operating unit${unitCount === 1 ? '' : 's'}.`
}

export const INFRASTRUCTURE_MARKERS: InfrastructureMarker[] = [
  ...AIRPORT_SEEDS.map((seed, index) => ({
    category: 'airport' as const,
    city: seed.city,
    code: seed.code,
    id: `airport-${seed.code.toLowerCase()}`,
    importance: importanceFromFeatured(seed.featured),
    latitude: seed.latitude,
    longitude: seed.longitude,
    note: airportNote(seed.featured),
    sortOrder: index + 1,
    stateCode: seed.stateCode,
    subtitle: `${seed.code} · ${seed.city}, ${seed.stateCode}`,
    title: normalizeAirportName(seed.airport),
  })),
]
